CACHE_TEMPLATE="$HOME/.claude/cache/ClaudeCodeTools/dev-closed-loop/CLAUDE_TEMPLATE.md"
DEPLOYED_VERSION="7.1.0"
echo "===migration-block-check==="
awk -v dep="v$DEPLOYED_VERSION" '
  /<!--$/ { p=1; b=""; next }
  /^-->$/ {
    if (p && b ~ /migration-notes/) {
      fv = ""
      if (match(b, /from-version:[ \t]*[^\n]+/)) {
        fv = substr(b, RSTART, RLENGTH)
        sub(/^from-version:[ \t]*/, "", fv)
      }
      if (fv != "") {
        pat = fv
        gsub(/\./, "\\.", pat)
        gsub(/x/, "[0-9]+", pat)
        if (dep ~ ("^" pat "(\\.[0-9]+)?$")) print b
      }
    }
    p=0
  }
  p { b=b"\n" }
' "$CACHE_TEMPLATE"
echo "===END==="
echo "===cache-version-line==="
grep -n "closed-loop v" "$CACHE_TEMPLATE" | head -1

